mapper.select:
SELECT faq_seq ,category ,question ,answer ,sort_seq ,use_yn ,rgst_date_time FROM event.tb_faq
AND category = #{category}
ORDER BY sort_seq, faq_seq

mapper.update:
UPDATE event.tb_faq
SET  category       = #{category}
    ,question       = #{question}
    ,answer         = #{answer}
    ,sort_seq       = #{sortSeq}
    ,use_yn         = #{useYn}
    ,upt_user_seq   = #{uptUserSeq}
    ,upt_date_time  = CURRENT_TIMESTAMP
WHERE faq_seq = #{faqSeq}
